Public class ETGBillExchangeDP
{
    ETGBillExchangeContract  billExchangeContract;
    ETGBillExchangeTempTable billExchangeTemp;
}

Method.Source:
public static ETGBillExchangeDP construct()
{
    ETGBillExchangeDP  dataProvider;

    dataProvider = new ETGBillExchangeDP();

    return dataProvider;
}

public ETGBillExchangeTempTable processReport (ETGBillExchangeContract _contract)
{
    SalesIdBase                           saleId;
    CustInvoiceId                         invoiceNum;
    CustInvoiceJour                       custInvoiceJour;
    SalesTable                            salesTable;
    SalesLine                             salesLine;
    LogisticsPostalAddress                logisticsPostalAddress;

    saleId     = _contract.parmSalesId();
    invoiceNum = _contract.parmSalesInvoiceId();

    salesTable      = SalesTable::find(saleId, false);
    custInvoiceJour = CustInvoiceJour::findFromSalesId(saleId);

    billExchangeTemp.SalesId          = salesTable.SalesId;
    billExchangeTemp.SalesInvoiceId   = custInvoiceJour.InvoiceId;
    billExchangeTemp.SalesInvoiceDate = custInvoiceJour.InvoiceDate;
    ttsbegin;
    billExchangeTemp.insert();
    ttscommit;

    select billExchangeTemp;
    return billExchangeTemp;
}
